/**
 * @summary Get recent deployment logs
 */
export const getGetDeploymentLogsUrl = (
  id: number,
  params?: GetDeploymentLogsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/deployments/${id}/logs?${stringifiedParams}`
    : `/api/deployments/${id}/logs`;
};

export const getDeploymentLogs = async (
  id: number,
  params?: GetDeploymentLogsParams,
  options?: RequestInit,
): Promise<BotLog[]> => {
  return customFetch<BotLog[]>(getGetDeploymentLogsUrl(id, params), {
    ...options,
    method: "GET",
  });
};

